server/tests/test_raster.py :: test_unsupported_channel_count_raises
def test_unsupported_channel_count_raises() -> None:
    raster = Raster(1, 1, 1, bytearray([128]))
    try:
        raster.to_rgb()
    except ValueError as error:
        assert "Unsupported channel count" in str(error)
    else:
        raise AssertionError("Expected ValueError")
